        rebalance_freq = 21
        min_bars = 252

        def get_px(sym, i, lag=0):
            if sym not in data:
                return None
            px = data[sym]['close']
            idx = i - lag
            if idx < 0 or idx >= len(px):
                return None
            v = float(px.iloc[idx])
            return v if v > 0 else None

        def momentum_12_1(sym, i):
            # 12-1 month: skip last month to avoid reversal
            p1  = get_px(sym, i, 21)   # 1-month-ago price
            p12 = get_px(sym, i, 252)  # 12-month-ago price
            if p1 is None or p12 is None:
                return None
            return p1 / p12 - 1.0

        def above_sma(sym, i, w=200):
            if sym not in data:
                return False
            px = data[sym]['close']
            if i < w:
                return False
            return float(px.iloc[i]) > float(px.iloc[i - w:i].mean())

        def get_macro(key, date):
            try:
                v = self.macro.get(key, date)
                return float(v) if v is not None else None
            except Exception:
                return None

        for i, date in enumerate(dates):
            if i < min_bars or i % rebalance_freq != 0:
                continue

            vix = get_macro('VIXCLS', date)

            agg_scores = {}
            for s in aggressive:
                sc = momentum_12_1(s, i)
                if sc is not None:
                    agg_scores[s] = sc

            def_scores = {}
