                continue

            extreme_panic  = vix is not None and vix > 40   # contrarian buy
            high_stress    = vix is not None and vix > 28   # cautious

            # Assets with positive 12-1 momentum AND above 200d SMA
            valid_agg = {s: sc for s, sc in agg_scores.items()
