                candidates = {s: sc for s, sc in agg_scores.items() if above_sma(s, i)}
                if not candidates:
                    candidates = agg_scores
                if candidates:
                    best = max(candidates, key=candidates.get)
                    nw[best] = 0.85
                    # Add TLT hedge in case panic deepens
                    if 'TLT' in def_scores:
                        nw['TLT'] = 0.10

            elif valid_agg and not high_stress:
                # Normal bull: concentrated single-asset conviction
                sorted_agg = sorted(valid_agg.items(), key=lambda x: x[1], reverse=True)
                best = sorted_agg[0][0]
                nw[best] = 0.90
                # Tiny diversification to second if 3+ valid assets and scores spread
                if len(sorted_agg) >= 3:
                    nw[sorted_agg[1][0]] = 0.05

            elif valid_agg and high_stress:
                # Elevated VIX but momentum still positive: partial equity + defensive hedge
                best_eq = max(valid_agg, key=valid_agg.get)
                nw[best_eq] = 0.55
                if def_scores:
                    best_def = max(def_scores, key=def_scores.get)
                    nw[best_def] = 0.35

