                if def_scores:
                    sorted_def = sorted(def_scores.items(), key=lambda x: x[1], reverse=True)
                    nw[sorted_def[0][0]] = 0.85
                    if len(sorted_def) > 1 and sorted_def[1][1] > 0:
                        nw[sorted_def[1][0]] = 0.10
                elif agg_scores:
                    # No defensive option, hold best equity small
                    best = max(agg_scores, key=agg_scores.get)
                    nw[best] = 0.30

            # Hard cap
            total = sum(nw.values())
            if total > 0.95:
                nw = {s: w * 0.95 / total for s, w in nw.items()}

            # Emit signals
            for sym in symbols:
                nw_val = nw.get(sym, 0.0)
                ow     = last_w.get(sym, 0.0)
                if ow < 0.001 and nw_val >= 0.001:
                    out[sym].at[date, 'signal']   = 1
                    out[sym].at[date, 'size_pct'] = nw_val
                elif ow >= 0.001 and nw_val < 0.001:
