                    out[sym].at[date, 'size_pct'] = 0.0
                elif ow >= 0.001 and nw_val >= 0.001 and abs(nw_val - ow) > 0.03:
                    out[sym].at[date, 'signal']   = 2
                    out[sym].at[date, 'size_pct'] = nw_val

            last_w = {s: nw.get(s, 0.0) for s in symbols}

        return out
